// ── 1) const everywhere const works ───────────────
// ❌ Creates a fresh TextStyle each build
Text('Hello', style: TextStyle(fontSize: 16, color: Colors.blue));
// ✅ Const, identity-equal, skipped on rebuild
const Text('Hello', style: TextStyle(fontSize: 16, color: Colors.blue));

// ── 2) Selector / select — narrow the subscription ──
// Riverpod
final cartItemsProvider = NotifierProvider<Cart, CartState>(Cart.new);
class CartCount extends ConsumerWidget {
  const CartCount({super.key});
  @override Widget build(_, ref) {
    // Only rebuilds when count changes, not when prices/coupons change
    final count = ref.watch(cartItemsProvider.select((s) => s.items.length));
    return Badge(label: Text('$count'));
  }
}

// Provider
Selector<CartModel, int>(
  selector: (_, c) => c.items.length,
  builder: (_, count, __) => Badge(label: Text('$count')),
)

// BLoC
BlocSelector<CartCubit, CartState, int>(
  selector: (s) => s.items.length,
  builder: (_, count) => Badge(label: Text('$count')),
)

