// ── Precache before navigation ─────────────────────
Future<void> openDetails(BuildContext context, Product p) async {
  // Decode the hero image before we push, so the destination page paints instantly
  await precacheImage(NetworkImage(p.heroUrl), context);
  if (context.mounted) {
    Navigator.of(context).push(MaterialPageRoute(builder: (_) => Details(product: p)));
  }
}

