import 'package:flutter_blurhash/flutter_blurhash.dart';
ClipRRect(
  borderRadius: BorderRadius.circular(8),
  child: AspectRatio(
    aspectRatio: 1,
    child: Stack(fit: StackFit.expand, children: [
