// ── Opacity — prefer color alpha for static content ─
// ❌ saveLayer per build, expensive
Opacity(opacity: 0.5, child: const Text('disabled'));

// ✅ shader-level blend, no offscreen buffer
Text('disabled', style: TextStyle(color: Colors.black.withValues(alpha: 0.5)));

// ✅ AnimatedOpacity / FadeTransition — smarter than Opacity
AnimatedOpacity(
  opacity: _visible ? 1.0 : 0.0,
  duration: const Duration(milliseconds: 200),
  child: const HelpTooltip(),
);

// ── BackdropFilter — limit to small areas, cache when static ──
// ❌ Full-screen frosted glass — expensive every frame
BackdropFilter(
  filter: ImageFilter.blur(sigmaX: 20, sigmaY: 20),
  child: Container(color: Colors.white24),
);

// ✅ Constrain the blur to the area that actually needs it
ClipRect(
  child: SizedBox(
    width: 320, height: 64,
    child: BackdropFilter(
      filter: ImageFilter.blur(sigmaX: 12, sigmaY: 12),
      child: const ColoredBox(color: Color(0x66FFFFFF)),
    ),
  ),
);

// ✅ Wrap in RepaintBoundary so the blur isn't recomputed when content under it didn't change
RepaintBoundary(
  child: BackdropFilter(
    filter: ImageFilter.blur(sigmaX: 12, sigmaY: 12),
    child: const SizedBox.expand(),
  ),
);

