class FeedPage extends StatelessWidget {
  const FeedPage({super.key, required this.posts});
  final List<Post> posts;

  @override
  Widget build(BuildContext context) {
    return ListView.builder(
      itemCount: posts.length,
      // ✅ Fixed height — Flutter skips per-item layout
      itemExtent: 96,
      cacheExtent: 600,        // ✅ render a bit off-screen for smoother scroll
      // ✅ Hand off scroll physics to platform conventions
      physics: const BouncingScrollPhysics(),
      itemBuilder: (_, i) => PostTile(post: posts[i]),
    );
  }
}

// PostTile is const-friendly and isolates its image
class PostTile extends StatelessWidget {
  const PostTile({super.key, required this.post});
  final Post post;

  @override
  Widget build(BuildContext context) {
    return RepaintBoundary(            // ✅ image raster isolated from neighbours
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
        child: Row(children: [
          ClipRRect(
            borderRadius: BorderRadius.circular(8),
            child: CachedNetworkImage(
              imageUrl: post.thumbUrl,
              width: 64, height: 64, fit: BoxFit.cover,
              memCacheWidth: 128, memCacheHeight: 128,  // ✅ right-size decode
            ),
          ),
          const SizedBox(width: 12),
          Expanded(child: _Body(post: post)),
        ]),
      ),
    );
  }
}

class _Body extends StatelessWidget {
  const _Body({required this.post});
  final Post post;
  @override
  Widget build(BuildContext context) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        Text(post.title, style: const TextStyle(fontWeight: FontWeight.w600), maxLines: 1, overflow: TextOverflow.ellipsis),
        const SizedBox(height: 4),
        Text(post.preview, style: const TextStyle(color: Colors.black54), maxLines: 2, overflow: TextOverflow.ellipsis),
      ],
    );
  }
}

// Paginated alternative for endless feeds
import 'package:infinite_scroll_pagination/infinite_scroll_pagination.dart';
final _ctrl = PagingController<int, Post>(firstPageKey: 0);
_ctrl.addPageRequestListener((page) async {
  final result = await api.feed(page: page, size: 30);
  result.last ? _ctrl.appendLastPage(result.items) : _ctrl.appendPage(result.items, page + 1);
});
PagedListView<int, Post>(
  pagingController: _ctrl,
  builderDelegate: PagedChildBuilderDelegate<Post>(
    itemBuilder: (_, post, __) => PostTile(post: post),
  ),
);
